<template>
  <div id="app">
    <router-view name="homePage" />
    <router-view :actorsData="topActors" :meow="bla" />
    <div class="over-limit-resolution">Over 4k</div>
  </div>
</template>

<script>
import { getActors } from "./util/TheMoveDatabase";
export default {
  name: "App",
  data() {
    return {
      topActors: [],
      bla: false,
    };
  },
  created() {
    getActors.then((result) => {
      // console.log(result);
      this.topActors = result;
    });

    this.apple();
  },
  methods: {
    apple() {
      setTimeout(() => {
        this.bla = true;
      }, 5000);
    },
  },
};
</script>

