import { gsap } from "gsap";
const startGsapHomeAnimation = (
  containerElClass,
  delayShowInfoElClass,
  delayShowBtnElClass
) => {
  const gsapTimeline = gsap.timeline();
  gsapTimeline.fromTo(
    `.${containerElClass}`,
    { xPercent: "-100" },
    {
      xPercent: "0",
      duration: "1",
      onComplete: () => {
        gsapTimeline
          .fromTo(`.${delayShowInfoElClass}`, { opacity: "0" }, { opacity: "1", duration: 1}, 1.2)
          .fromTo(
            `.${delayShowBtnElClass}`,
            { display: "none", opacity: "0" },
            { display: "block", opacity: "1", duration:1 },
            1.7
          );
      },
    }
  );
  return gsapTimeline;
};

export { startGsapHomeAnimation };
